(window.webpackJsonp=window.webpackJsonp||[]).push([[561],{830:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">mat</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> diagonalSum = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">mat</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> priSum=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> secSum=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> m=mat.length\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;m;i++){\\n        priSum+=mat[i][i]\\n        secSum+=mat[i][m-i<span class=\\"hljs-number\\">-1</span>]\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(priSum,secSum)</span>\\n    <span class=\\"hljs-keyword\\">if</span>(m % <span class=\\"hljs-number\\">2</span>===<span class=\\"hljs-number\\">0</span>){\\n        <span class=\\"hljs-keyword\\">return</span> priSum+secSum\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.floor(m/<span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">return</span> priSum+secSum - mat[mid][mid]\\n\\n};\\n</code></pre>\\n"],"titleSlug":"matrix-diagonal-sum","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6b63\u65b9\u5f62\u77e9\u9635 <code>mat</code>\uff0c\u8bf7\u4f60\u8fd4\u56de\u77e9\u9635\u5bf9\u89d2\u7ebf\u5143\u7d20\u7684\u548c\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u5728\u77e9\u9635\u4e3b\u5bf9\u89d2\u7ebf\u4e0a\u7684\u5143\u7d20\u548c\u526f\u5bf9\u89d2\u7ebf\u4e0a\u4e14\u4e0d\u5728\u4e3b\u5bf9\u89d2\u7ebf\u4e0a\u5143\u7d20\u7684\u548c\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b&nbsp; 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/08/14/sample_1911.png\\" style=\\"height:174px; width:336px\\" /></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>mat = [[<strong>1</strong>,2,<strong>3</strong>],\\n&nbsp;           [4,<strong>5</strong>,6],\\n&nbsp;           [<strong>7</strong>,8,<strong>9</strong>]]\\n<strong>\u8f93\u51fa\uff1a</strong>25\\n<strong>\u89e3\u91ca\uff1a</strong>\u5bf9\u89d2\u7ebf\u7684\u548c\u4e3a\uff1a1 + 5 + 9 + 3 + 7 = 25\\n\u8bf7\u6ce8\u610f\uff0c\u5143\u7d20 mat[1][1] = 5 \u53ea\u4f1a\u88ab\u8ba1\u7b97\u4e00\u6b21\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b&nbsp; 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>mat = [[<strong>1</strong>,1,1,<strong>1</strong>],\\n&nbsp;           [1,<strong>1</strong>,<strong>1</strong>,1],\\n&nbsp;           [1,<strong>1</strong>,<strong>1</strong>,1],\\n&nbsp;           [<strong>1</strong>,1,1,<strong>1</strong>]]\\n<strong>\u8f93\u51fa\uff1a</strong>8\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>mat = [[<strong>5</strong>]]\\n<strong>\u8f93\u51fa\uff1a</strong>5\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>n == mat.length == mat[i].length</code></li>\\n\\t<li><code>1 &lt;= n &lt;= 100</code></li>\\n\\t<li><code>1 &lt;= mat[i][j] &lt;= 100</code></li>\\n</ul>\\n","title":"1572. \u77e9\u9635\u5bf9\u89d2\u7ebf\u5143\u7d20\u7684\u548c","relatedTags":["\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1572"}')}}]);